import React from 'react';
import {
  View,
  Text,
  TouchableOpacity,
  StyleSheet,
  ScrollView,
  Image,
  StatusBar,
  Dimensions,
  Share
} from 'react-native';
import { MaterialCommunityIcons, MaterialIcons } from '@expo/vector-icons';
import { useApp } from '../context/AppContext';
import { t } from '../utils/i18n';

const { width } = Dimensions.get('window');

const ResultsScreen = ({ navigation, route }) => {
  const { language } = useApp();
  const { result, imageUri } = route.params || {};
  const detection = result?.detection || {};
  const predictions = result?.predictions || [];
  const diseaseInfo = result?.disease_info || {};
  const translations = result?.translations || {};
  const confidencePercent = Math.round((detection.confidence || 0) * 100);

  // Get localized content from AI result or fallback to English
  const localizedTitle = translations[language]?.name || detection.disease_name;
  const localizedSymptoms = translations[language]?.symptoms || diseaseInfo.symptoms;
  const localizedTreatment = translations[language]?.treatment || diseaseInfo.treatment;
  const localizedPrevention = translations[language]?.prevention || diseaseInfo.prevention;

  const onShare = async () => {
    try {
      await Share.share({
        message: `Murimi App Detection Result: ${detection.disease_name || 'Crop Disease'} detected with ${confidencePercent}% confidence.`,
      });
    } catch (error) {
      console.error(error.message);
    }
  };

  return (
    <View style={styles.container}>
      <StatusBar barStyle="dark-content" backgroundColor="#FFF" />

      {/* Header */}
      <View style={styles.header}>
        <TouchableOpacity style={styles.backBtn} onPress={() => navigation.goBack()}>
          <MaterialIcons name="arrow-back" size={24} color="#2c5926" />
        </TouchableOpacity>
        <Text style={styles.headerTitle}>{t('results', language)}</Text>
        <TouchableOpacity style={styles.shareBtn} onPress={onShare}>
          <MaterialIcons name="share" size={24} color="#2c5926" />
        </TouchableOpacity>
      </View>

      <ScrollView contentContainerStyle={styles.scrollContent}>
        {/* Hero Section with Image and Badge */}
        <View style={styles.heroSection}>
          <Image source={{ uri: imageUri || 'https://lh3.googleusercontent.com/aida-public/AB6AXuAbD3L9qev4hSutFvI651ZejiAfJGgTmbyb68hsrtW66aubhNmjOrldw5smTBKEMlssqmZdM8uJn6P3v2G8Nv86iHn6a9G8WLR-ChZKxuWlrqpiZHeTeFdEUh0d2TRqYn2XIeIXlptmoa9aQ9jePt-ydmaxeZNCBqmSIXlXAJ1gGMUFNQexnYjRLmnS32YkgoBcUHX6t7ZR37dBelC4RoTaMm5l-PUo5QA0xi3KCWp5PayjCNrVG1TcELi6Xs0khMSQBIeyGop-bCA' }} style={styles.heroImage} />
          <View style={styles.gradientOverlay} />

          <View style={styles.imageBadge}>
            <MaterialIcons name="verified" size={16} color="#FFF" style={styles.badgeIcon} />
            <Text style={styles.badgeText}>{confidencePercent}% {t('confidence', language)}</Text>
          </View>

          <Text style={styles.diseaseTitle}>{localizedTitle || 'Maize Streak Virus'}</Text>
        </View>

        {/* Symptoms Section */}
        <View style={styles.infoCard}>
          <View style={styles.infoContent}>
            <View style={styles.cardHeader}>
              <MaterialIcons name="info" size={20} color="#2c5926" />
              <Text style={styles.cardTitle}>{t('symptoms', language)}</Text>
            </View>
            <Text style={styles.cardBody}>
              {localizedSymptoms || "Look for broken, yellowish to white streaks that run parallel to the leaf veins. Streaks are usually uniform in width and distributed throughout the leaf surface, starting from the base."}
            </Text>
          </View>
        </View>

        {/* Treatment Steps */}
        <View style={styles.section}>
          <View style={styles.sectionHeader}>
            <MaterialIcons name="healing" size={22} color="#2c5926" />
            <Text style={styles.sectionTitle}>{t('treatment', language)}</Text>
          </View>

          <View style={styles.stepsList}>
            {(localizedTreatment || "Remove infected plants\nApply insecticides\nClear grassy weeds").split('\n').map((step, i) => (
              <View key={i} style={styles.stepItem}>
                <MaterialIcons name="check-circle" size={20} color="#2c5926" style={styles.stepIcon} />
                <Text style={styles.stepText}>{step.replace(/^\d+\.\s*/, '')}</Text>
              </View>
            ))}
          </View>
        </View>

        {/* Prevention */}
        <View style={styles.section}>
          <View style={styles.sectionHeader}>
            <MaterialIcons name="shield" size={22} color="#2c5926" />
