          </TouchableOpacity>

          <TouchableOpacity style={styles.secondaryBtn}>
            <MaterialIcons name="bookmark-border" size={24} color="#444" />
            <Text style={styles.secondaryBtnText}>{t('save_result', language)}</Text>
          </TouchableOpacity>
        </View>
      </ScrollView>

      {/* Bottom Nav Mockup */}
      <View style={styles.bottomNav}>
        <TouchableOpacity style={styles.navItem} onPress={() => navigation.navigate('Dashboard')}>
          <MaterialCommunityIcons name="home-outline" size={24} color="#9ca3af" />
          <Text style={styles.navText}>Home</Text>
        </TouchableOpacity>
        <TouchableOpacity style={styles.navItem} onPress={() => navigation.navigate('DiseaseDetection')}>
          <MaterialCommunityIcons name="focus-field" size={24} color="#2c5926" />
          <Text style={[styles.navText, { color: '#2c5926' }]}>Scan</Text>
        </TouchableOpacity>
        <TouchableOpacity style={styles.navItem}>
          <MaterialCommunityIcons name="history" size={24} color="#9ca3af" />
          <Text style={styles.navText}>History</Text>
        </TouchableOpacity>
        <TouchableOpacity style={styles.navItem}>
          <MaterialCommunityIcons name="lightbulb-outline" size={24} color="#9ca3af" />
          <Text style={styles.navText}>Tips</Text>
        </TouchableOpacity>
      </View>
    </View>
  );
};

